import { useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useToast } from "@/hooks/use-toast";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { Link } from "wouter";
import { Truck, MapPin, Clock, CheckCircle2, Package, Phone } from "lucide-react";
import type { Delivery, Order } from "@shared/schema";

type DeliveryWithOrder = Delivery & {
  order: Order;
};

export default function DriverDashboard() {
  const { toast } = useToast();
  const { isDriver, isAuthenticated, isLoading: authLoading } = useAuth();

  useEffect(() => {
    if (!authLoading && (!isAuthenticated || !isDriver)) {
      toast({
        title: "Unauthorized",
        description: "You are logged out. Logging in again...",
        variant: "destructive",
      });
      setTimeout(() => {
        window.location.href = "/api/login";
      }, 500);
    }
  }, [isAuthenticated, isDriver, authLoading, toast]);

  const { data: activeDeliveries, isLoading: deliveriesLoading } = useQuery<DeliveryWithOrder[]>({
    queryKey: ["/api/driver/deliveries/active"],
    enabled: isAuthenticated && isDriver,
  });

  if (authLoading) {
    return (
      <div className="h-screen flex items-center justify-center">
        <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full" />
      </div>
    );
  }

  const getStatusBadge = (status: string) => {
    const variants: Record<string, { className: string; label: string }> = {
      pending: { className: "bg-chart-3 text-white", label: "Pending" },
      assigned: { className: "bg-chart-2 text-white", label: "Assigned" },
      picked_up: { className: "bg-primary text-primary-foreground", label: "Picked Up" },
      in_transit: { className: "bg-primary text-primary-foreground", label: "In Transit" },
      delivered: { className: "bg-chart-1 text-white", label: "Delivered" },
      failed: { className: "bg-destructive text-destructive-foreground", label: "Failed" },
    };
    const variant = variants[status] || variants.pending;
    return <Badge className={variant.className}>{variant.label}</Badge>;
  };

  return (
    <div className="space-y-8">
      <div>
        <h1 className="text-3xl font-bold mb-2">Active Deliveries</h1>
        <p className="text-muted-foreground">Manage your delivery queue and track progress</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <Card data-testid="card-pending">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Pending</CardTitle>
            <Clock className="h-4 w-4 text-chart-3" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-chart-3">
              {activeDeliveries?.filter(d => d.status === 'pending' || d.status === 'assigned').length || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">Awaiting pickup</p>
          </CardContent>
        </Card>

        <Card data-testid="card-in-transit">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">In Transit</CardTitle>
            <Truck className="h-4 w-4 text-primary" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-primary">
              {activeDeliveries?.filter(d => d.status === 'picked_up' || d.status === 'in_transit').length || 0}
            </div>
            <p className="text-xs text-muted-foreground mt-1">On the way</p>
          </CardContent>
        </Card>

        <Card data-testid="card-completed-today">
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Completed Today</CardTitle>
            <CheckCircle2 className="h-4 w-4 text-chart-1" />
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">0</div>
            <p className="text-xs text-muted-foreground mt-1">Delivered successfully</p>
          </CardContent>
        </Card>
      </div>

      <Card data-testid="card-delivery-queue">
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle>Delivery Queue</CardTitle>
              <CardDescription>Your assigned deliveries</CardDescription>
            </div>
            <Button asChild data-testid="button-view-history">
              <Link href="/driver/history">View History</Link>
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {deliveriesLoading ? (
            <div className="space-y-4">
              {Array.from({ length: 3 }).map((_, i) => (
                <div key={i} className="flex items-start gap-4 p-4 border border-border rounded-md">
                  <Skeleton className="h-12 w-12 rounded-md" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-4 w-48" />
                    <Skeleton className="h-3 w-64" />
                    <Skeleton className="h-3 w-32" />
                  </div>
                  <Skeleton className="h-9 w-24" />
                </div>
              ))}
            </div>
          ) : activeDeliveries && activeDeliveries.length > 0 ? (
            <div className="space-y-3">
              {activeDeliveries.map((delivery) => (
                <div 
                  key={delivery.id} 
                  className="flex items-start gap-4 p-4 border border-border rounded-md hover-elevate active-elevate-2"
                  data-testid={`delivery-item-${delivery.id}`}
                >
                  <div className="w-12 h-12 rounded-md bg-muted flex items-center justify-center">
                    <Package className="w-6 h-6 text-muted-foreground" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-start justify-between mb-2">
                      <div>
                        <p className="font-semibold">Order #{delivery.orderId.slice(0, 8)}</p>
                        <p className="text-sm text-muted-foreground">
                          Total: MK {parseFloat(delivery.order.total).toFixed(2)}
                        </p>
                      </div>
                      {getStatusBadge(delivery.status)}
                    </div>
                    <div className="space-y-1 text-sm">
                      <div className="flex items-center gap-2 text-muted-foreground">
                        <MapPin className="w-4 h-4" />
                        <span className="line-clamp-1">{delivery.order.deliveryAddress || 'Address not provided'}</span>
                      </div>
                      {delivery.order.customerPhone && (
                        <div className="flex items-center gap-2 text-muted-foreground">
                          <Phone className="w-4 h-4" />
                          <span>{delivery.order.customerPhone}</span>
                        </div>
                      )}
                      {delivery.order.deliveryDistance && (
                        <p className="text-xs text-muted-foreground">
                          Distance: {parseFloat(delivery.order.deliveryDistance).toFixed(1)} km
                        </p>
                      )}
                    </div>
                  </div>
                  <div className="flex flex-col gap-2">
                    <Button size="sm" data-testid={`button-view-${delivery.id}`}>View Details</Button>
                    {delivery.status === 'assigned' && (
                      <Button size="sm" variant="outline" data-testid={`button-pickup-${delivery.id}`}>
                        Mark Picked Up
                      </Button>
                    )}
                    {(delivery.status === 'picked_up' || delivery.status === 'in_transit') && (
                      <Button size="sm" variant="outline" data-testid={`button-deliver-${delivery.id}`}>
                        Mark Delivered
                      </Button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="text-center py-12">
              <Truck className="w-12 h-12 mx-auto mb-4 text-muted-foreground opacity-50" />
              <p className="text-muted-foreground">No active deliveries</p>
              <p className="text-sm text-muted-foreground mt-1">New deliveries will appear here when assigned</p>
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/App.tsx.content:
import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { SidebarProvider, SidebarTrigger } from "@/components/ui/sidebar";
import { AppSidebar } from "@/components/app-sidebar";
import { ThemeProvider } from "@/contexts/ThemeProvider";
import { ThemeToggle } from "@/components/ThemeToggle";
import { useAuth } from "@/hooks/useAuth";
import NotFound from "@/pages/not-found";
import Landing from "@/pages/landing";
import CustomerHome from "@/pages/customer/home";
import AdminDashboard from "@/pages/admin/dashboard";
import PharmacistDashboard from "@/pages/pharmacist/dashboard";
import POSPage from "@/pages/pos";
import DriverDashboard from "@/pages/driver/dashboard";

function AdminLayout({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex h-screen w-full">
      <AppSidebar />
      <div className="flex flex-col flex-1">
        <header className="flex items-center justify-between p-2 border-b">
          <SidebarTrigger data-testid="button-sidebar-toggle" />
          <ThemeToggle />
        </header>
        <main className="flex-1 overflow-auto">
          <div className="container mx-auto p-6 max-w-7xl">
            {children}
          </div>
        </main>
      </div>
    </div>
  );
}

function Router() {
  const { isAuthenticated, isLoading, isCustomer, isAdmin, isPharmacist, isStaff, isDriver } = useAuth();

  if (isLoading) {
    return (
      <div className="h-screen flex items-center justify-center">
        <div className="animate-spin w-8 h-8 border-4 border-primary border-t-transparent rounded-full" aria-label="Loading"/>
      </div>
    );
  }

  // Customer routes
  if (isAuthenticated && isCustomer) {
    const CustomerShop = require("@/pages/customer/shop").default;
    const CustomerOrders = require("@/pages/customer/orders").default;
    const CustomerOrderDetail = require("@/pages/customer/order-detail").default;
    const CustomerPrescriptions = require("@/pages/customer/prescriptions").default;
    const CustomerProfile = require("@/pages/customer/profile").default;
    const CartPage = require("@/pages/customer/cart").default;
    const CheckoutPage = require("@/pages/customer/checkout").default;
    const ConsultationsPage = require("@/pages/customer/consultations").default;

    return (
      <Switch>
        <Route path="/" component={CustomerHome} />
        <Route path="/shop" component={CustomerShop} />
        <Route path="/cart" component={CartPage} />
        <Route path="/checkout" component={CheckoutPage} />
        <Route path="/orders" component={CustomerOrders} />
        <Route path="/orders/:id" component={CustomerOrderDetail} />
        <Route path="/prescriptions" component={CustomerPrescriptions} />
        <Route path="/consultations" component={ConsultationsPage} />
        <Route path="/profile" component={CustomerProfile} />
        <Route component={NotFound} />
      </Switch>
    );
  }

  // Not authenticated - show landing/login
  if (!isAuthenticated) {
    return (
      <Switch>
        <Route path="/" component={Landing} />
        <Route component={NotFound} />
      </Switch>
    );
  }

  // Staff/Admin/Pharmacist/Driver routes
  return (
    <Switch>
      {isAdmin && (
        <>
          <Route path="/admin">
            <AdminLayout><AdminDashboard /></AdminLayout>
          </Route>
          <Route path="/admin/dashboard">
            <AdminLayout><AdminDashboard /></AdminLayout>
          </Route>
          <Route path="/admin/inventory">
            {() => {
              const AdminInventory = require("@/pages/admin/inventory").default;
              return <AdminLayout><AdminInventory /></AdminLayout>;
            }}
          </Route>
        </>
      )}
      {isPharmacist && (
        <>
          <Route path="/pharmacist">
            <AdminLayout><PharmacistDashboard /></AdminLayout>
          </Route>
          <Route path="/pharmacist/dashboard">
            <AdminLayout><PharmacistDashboard /></AdminLayout>
          </Route>
          <Route path="/pharmacist/prescriptions">
            {() => {
              const PharmacistPrescriptions = require("@/pages/pharmacist/prescriptions").default;
              return <AdminLayout><PharmacistPrescriptions /></AdminLayout>;
            }}
          </Route>
          <Route path="/pharmacist/prescriptions/:id">
            {() => {
              const PharmacistPrescriptionDetail = require("@/pages/pharmacist/prescription-detail").default;
              return <AdminLayout><PharmacistPrescriptionDetail /></AdminLayout>;
            }}
          </Route>
        </>
      )}
      {isStaff && (
        <>
          <Route path="/pos" component={POSPage} />
        </>
      )}
      {isDriver && (
        <>
          <Route path="/driver">
            <AdminLayout><DriverDashboard /></AdminLayout>
          </Route>
        </>
      )}

      {/* Default route based on role */}
      <Route path="/">
        {isAdmin ? (
          <AdminLayout><AdminDashboard /></AdminLayout>
        ) : isPharmacist ? (
          <AdminLayout><PharmacistDashboard /></AdminLayout>
        ) : isStaff ? (
          <POSPage />
        ) : isDriver ? (
          <AdminLayout><DriverDashboard /></AdminLayout>
        ) : (
          <Landing />
        )}
      </Route>

      <Route component={NotFound} />
    </Switch>
  );
}

export default function App() {
  const style = {
    "--sidebar-width": "16rem",
    "--sidebar-width-icon": "3rem",
  };

  return (
    <QueryClientProvider client={queryClient}>
      <ThemeProvider>
        <TooltipProvider>
          <SidebarProvider style={style as React.CSSProperties}>
            <Toaster />
            <Router />
          </SidebarProvider>
        </TooltipProvider>
      </ThemeProvider>
    </QueryClientProvider>
  );
}

