import { DatabaseStorage } from "./storage";
import { MemoryStorage } from "./memoryStorage";
import type { IStorage } from "./storage";

let storageInstance: IStorage | null = null;
let useMemory = false;

export function getStorage(): IStorage {
  if (!storageInstance) {
    // Try to use database, but fall back to memory if it's disabled
    useMemory = process.env.USE_MEMORY_STORAGE === 'true';

    if (useMemory) {
      console.log("Using in-memory storage");
      storageInstance = new MemoryStorage();
    } else {
      console.log("Using database storage");
      storageInstance = new DatabaseStorage();
    }
  }

  return storageInstance;
}

export function setUseMemory(value: boolean) {
  useMemory = value;
  storageInstance = null; // Reset so it creates a new instance next time
}

